use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::Path;

struct Row {
    id: i32,
    name: String,
    scores: Vec<f64>,
}

fn read_csv(filename: &str) -> Vec<Row> {
    let file = File::open(filename).expect("Failed to open file");
    let reader = BufReader::new(file);

    reader.lines()
        .map(|line| {
            let line = line.expect("Failed to read line");
            let mut parts = line.split(',');
            let id = parts.next().unwrap().parse::<i32>().expect("Invalid id");
            let name = parts.next().unwrap().to_string();
            let scores: Vec<f64> = parts
                .map(|s| s.parse().unwrap())
                .collect();

            Row { id, name, scores }
        })
        .collect()
}

fn calculate_average_score(row: &Row) -> (f64, String) {
    let sum: f64 = row.scores.iter().sum();
    let average = sum / row.scores.len() as f64;
    (average, format!("{:.1}", average))
}

fn process_csv(filename: &str) -> Vec<(i32, String, f64)> {
    let rows = read_csv(filename);
    rows.into_iter()
        .map(|row| {
            let (average, average_score) = calculate_average_score(&row);
            (row.id, row.name, average_score)
        })
        .collect()
}

fn main() {
    let filename = "input.csv";
    let output = process_csv(filename);
    for (id, name, average_score) in output {
        println!("({}, {}, {})", id, name, average_score);
    }
}
