        this.teamName = teamName;
        this.numMembers = numMembers;
    }

    public void addChild(TreeNode child) {
        if (children.size() < 3) {
            children.add(child);
        }
    }
}

class OrganizationTree {
    TreeNode organization;

    public OrganizationTree(List<Team> teams) {
        organization = new TreeNode("Organization", 0);
        for (Team team : teams) {
            TreeNode teamNode = new TreeNode(team.teamName, team.members.size());
            teamNode.addChild(new TreeNode(team.teamName, team.members.size()));
            teamNode.addChild(new TreeNode(team.teamName, team.members.size()));
            organization.addChild(teamNode);
        }
    }
}

