#include <string>
#include <algorithm>

using namespace std;

struct Employee {
    string name;
    vector<int> salaries;
};

struct Node {
    int value;
    vector<Node*> children;
};

Node* buildTree(vector<Employee>& employees, vector<pair<string, string>>& hierarchy) {
    if (employees.empty()) return nullptr;

    vector<Node*> nodes;
    for (const auto& employee : employees) {
        Node* node = new Node{employee.salaries[0]};
        nodes.push_back(node);
    }

    for (const auto& pair : hierarchy) {
        string manager = pair.first;
        string employee = pair.second;

        auto managerNode = find_if(nodes.begin(), nodes.end(), [&](Node* node) { return node->name == manager; });
        auto employeeNode = find_if(nodes.begin(), nodes.end(), [&](Node* node) { return node->name == employee; });

        if (managerNode && employeeNode) {
            managerNode->children.push_back(employeeNode);
            if (employeeNode->salaries.size() > 1) {
                Node* newNode = new Node{employeeNode->salaries[1]};
                employeeNode->children.push_back(newNode);
            }
        }
    }

    return find_if(nodes.begin(), nodes.end(), [&](Node* node) { return node->salaries.size() <= 1; });
}

void printTree(Node* node, int level = 0) {
    if (node) {
        for (int i = 0; i < level; ++i) cout << "  ";
        cout << node->value << endl;
        for (const auto& child : node->children) {
            printTree(child, level + 1);
        }
    }
}

int main() {
    vector<Employee> employees = {
        {"John", {10000, 12000}},
        {"Alice", {15000, 18000}},
        {"Bob", {20000, 22000}},
        {"Mike", {25000, 28000}}
    };

    vector<pair<string, string>> hierarchy = {
        {"John", "Alice"},
        {"Alice", "Bob"},
        {"John", "Mike"}
    };

    Node* root = buildTree(employees, hierarchy);

    printTree(root);

    return 0;
}
