import org.json.JSONArray;
import org.json.JSONObject;
import org.jgrapht.Graph;
import org.jgrapht.graph.DefaultDirectedGraph;
import org.jgrapht.graph.DefaultEdge;
import org.jgrapht.io.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.util.Arrays;

public class Main {

    public static void main(String[] args) throws IOException {
        Graph<Integer, DefaultEdge> graph = new DefaultDirectedGraph<>(DefaultEdge.class);
        readJsonFile(graph);
        printGraph(graph);
    }

    private static void readJsonFile(Graph<Integer, DefaultEdge> graph) throws IOException {
        File file = new File("employees.json");
        JSONArray jsonArray = new JSONArray(new FileReader(file));
        for (int i = 0; i < jsonArray.length(); i++) {
            JSONObject employee = jsonArray.getJSONObject(i);
            int id = employee.getInt("id");
            if (id < 100 || id > 999) {
                continue;
            }
            graph.addVertex(id);
            for (int j = 0; j < jsonArray.length(); j++) {
                if (i == j) {
                    continue;
                }
                JSONObject otherEmployee = jsonArray.getJSONObject(j);
                int otherId = otherEmployee.getInt("id");
                if (otherId < 100 || otherId > 999) {
                    continue;
                }
                int salaryDiff = Math.abs(employee.getInt("salary") - otherEmployee.getInt("salary"));
                if (salaryDiff < 5000 && graphEdgeCount(graph) < 50) {
                    graph.addEdge(id, otherId);
                    graph.setEdgeWeight(id, otherId, salaryDiff);
                }
            }
        }
    }

    private static int graphEdgeCount(Graph<Integer, DefaultEdge> graph) {
        return graph.edgeSet().size();
    }

    private static void printGraph(Graph<Integer, DefaultEdge> graph) {
        System.out.println(graph.toString());
    }
}
