tuple<vector<int>, vector<int>> computeTotalHoursWorked(const string& csvFilePath) {
    // Initialize a map to store the total hours worked for each employee
    map<int, int> employeeHours;

    // Read the CSV file
    ifstream file(csvFilePath);
    if (!file.is_open()) {
        cerr << "Failed to open the file." << endl;
        return make_tuple(vector<int>(), vector<int>());
    }

    string line, column;
    int EmployeeID, HoursWorked;

    // Read each line in the CSV file
    while (getline(file, line)) {
        istringstream iss(line);
        iss >> EmployeeID >> HoursWorked;

        // Update the total hours worked for the employee
        employeeHours[EmployeeID] += HoursWorked;
    }

    file.close();

    // Create a vector to store the sorted employee IDs
    vector<int> sortedEmployeeIDs;
    for (const auto& pair : employeeHours) {
        sortedEmployeeIDs.push_back(pair.first);
    }
    sort(sortedEmployeeIDs.begin(), sortedEmployeeIDs.end());

    // Create a vector to store the total hours worked for each employee
    vector<int> totalHours(sortedEmployeeIDs.size());
    for (size_t i = 0; i < sortedEmployeeIDs.size(); ++i) {
        totalHours[i] = employeeHours[sortedEmployeeIDs[i]];
    }

    // Scale the total hours worked for each employee to fall between [0, 160]
    for (int& hours : totalHours) {
        hours = min(160, max(hours, 0));
    }

    // Return the sorted total hours worked for each employee as a tuple
    return make_tuple(totalHours, sortedEmployeeIDs);
}

