use std::collections::HashMap;

#[derive(Debug, PartialEq)]
enum NodeType {
    Node {
        id: i32,
        children: Vec<i32>,
    },
}

#[derive(Debug, PartialEq)]
enum Tree {
    Tree {
        root: i32,
        children: HashMap<i32, Vec<i32>>,
    },
}

fn construct_tree(tuples: Vec<(i32, i32)>) -> Tree {
    let mut tree = Tree::Tree {
        root: 0,
        children: HashMap::new(),
    };

    let mut nodes = Vec::new();
    for (id, parent) in tuples {
        if parent == 0 {
            tree.children.insert(id, Vec::new());
            nodes.push(NodeType::Node {
                id,
                children: Vec::new(),
            });
        } else {
            if let Some(children) = tree.children.get_mut(&parent) {
                tree.children.insert(id, Vec::new());
                children.push(id);
                nodes.push(NodeType::Node {
                    id,
                    children: Vec::new(),
                });
            } else {
                panic!("Parent node not found in tree");
            }
        }
    }

    let mut visited = HashSet::new();
    for node in nodes {
        if node.id == 0 {
            continue;
        }
        dfs(node, &mut tree, &mut visited);
    }

    tree
}

fn dfs(node: NodeType, tree: &mut Tree, visited: &mut HashSet<i32>) {
    visited.insert(node.id);
    if tree.children.contains_key(&node.id) {
        for child in tree.children.get_mut(&node.id).unwrap() {
            if visited.contains(child) {
                panic!("Tree exceeds maximum depth of 3 levels");
            }
            dfs(NodeType::Node {
                id: *child,
                children: Vec::new(),
            }, tree, visited);
        }
    }
    if tree.children.contains_key(&node.id) && tree.children.get_mut(&node.id).unwrap().len() > 2 {
        panic!("Parent node has more than 2 children");
    }
}

fn main() {
    let tuples = vec![(1, 0), (2, 0), (3, 0), (4, 1), (5, 2), (6, 2), (7, 3)];
    let tree = construct_tree(tuples);
    println!("{:?}", tree);
}
