import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class Main {

    public static List<Integer> evaluateExpressions(String multiLineString) {
        String[] lines = multiLineString.split("\n");
        List<Integer> results = new ArrayList<>();

        for (String line : lines) {
            Pattern pattern = Pattern.compile("\\d+\\.?\\d*");
            Matcher matcher = pattern.matcher(line);
            StringBuilder expression = new StringBuilder();

            while (matcher.find()) {
                expression.append(matcher.group()).append(" ");
            }

            try {
                double result = Double.parseDouble(expression.toString().trim());
                if (result < 0) {
                    throw new ArithmeticException();
                }
                results.add((int) Math.round(result));
            } catch (ArithmeticException e) {
                // Ignore invalid expressions
            }
        }

        return results;
    }

    public static void main(String[] args) {
        String multiLineString = "2 + 3\n5 * 4\n-1\n1.2";
        List<Integer> results = evaluateExpressions(multiLineString);
        System.out.println(results);
    }
}
