def validate_email(email):
    if len(email) > 254:
        return False
    parts = email.split('@')
    if len(parts) != 2:
        return False
    local, domain = parts
    if not local or not domain:
        return False
    if '.' not in domain:
        return False
    local_parts = local.split('.')
    if len(local_parts) > 2:
        return False
    for part in local_parts:
        if len(part) > 63 or not part.isalnum():
            return False
    return True
